targets.expr:
((avg by (job) (
  sum without (id) (jvm_memory_used{area="heap", job!="",job=~"$job",instance=~"$instance"})
))/(avg by (job) (
  sum without (id) (jvm_memory_max{area="heap", job!="",job=~"$job",instance=~"$instance"} != -1)
))) * 100

((avg by (job) (
  sum without (id) (jvm_memory_used{area="nonheap", job!="",job=~"$job",instance=~"$instance"})
))/(avg by (job) (
  sum without (id) (jvm_memory_max{area="nonheap", job!="",job=~"$job",instance=~"$instance"} != -1)
))) * 100
